import{_ as a,o as r,c as i,j as t,a as n,aa as s}from"./chunks/framework.GPvTQ_Wl.js";const b=JSON.parse('{"title":"HTML UI Debugger","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/html-ui-debugger.md","filePath":"guide/html-ui-debugger.md","lastUpdated":1777504235000}'),l={name:"guide/html-ui-debugger.md"},c=["src"];function h(o,e,d,g,u,p){return r(),i("div",null,[e[0]||(e[0]=t("h1",{id:"html-ui-debugger",tabindex:"-1"},[n("HTML UI Debugger "),t("a",{class:"header-anchor",href:"#html-ui-debugger","aria-label":'Permalink to "HTML UI Debugger"'},"​")],-1)),t("p",null,[t("video",{src:o.$withBase("/videos/ui_debugger_showcase.mp4"),"data-title":"HTML UI Debugger Showcase",autoplay:"",loop:"",muted:"",playsinline:""},null,8,c)]),e[1]||(e[1]=s('<p>The <strong>HTML UI Debugger</strong> is an interactive tool for inspecting and manipulating the game&#39;s User Interface. It provides a visual tree view of all components, making it easier to understand hierarchies than using console commands alone.</p><div class="warning custom-block"><p class="custom-block-title">Experimental Feature</p><p>This tool is <strong>highly experimental</strong>. While functional, bugs and unexpected behavior are to be expected. Feedback, bug reports, and suggestions are <strong>highly welcome</strong> and critical for the tool&#39;s refinement.</p><p>Please report issues on the <strong><a href="https://github.com/bukowa/ConsulScriptum/issues" target="_blank" rel="noreferrer">GitHub Repository</a></strong>.</p></div><div class="tip custom-block"><p class="custom-block-title">Recommended Tool</p><p>This is the standard way to debug UI in Rome II, Attila, and ToB as of version <strong>0.8.0</strong>. It provides a live view of the UI state and allows for direct interaction with components.</p></div><h2 id="launching-the-debugger" tabindex="-1">Launching the Debugger <a class="header-anchor" href="#launching-the-debugger" aria-label="Permalink to &quot;Launching the Debugger&quot;">​</a></h2><p>To open the debugger, type the following command in the Consul console:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/debug_html</span></span></code></pre></div><p>This will generate the necessary debugger files and automatically open the interface in your default web browser.</p><div class="warning custom-block"><p class="custom-block-title">Safe Path</p><p>To bypass browser security restrictions (which block access to <code>Program Files</code>), the debugger now saves all state and command files to a &quot;neutral&quot; system location: <code>C:\\Users\\Public\\consul\\&lt;GAME&gt;\\uidebug</code></p></div><h2 id="connecting-the-debugger" tabindex="-1">Connecting the Debugger <a class="header-anchor" href="#connecting-the-debugger" aria-label="Permalink to &quot;Connecting the Debugger&quot;">​</a></h2><p>Because the debugger runs as a web page, it requires permission to read the state files generated by the game.</p><ol><li><strong>Copy the Path</strong>: In the browser window, look for <strong>STEP 1</strong>. Click the dashed box to copy the expected debug path to your clipboard.</li><li><strong>Click Connect</strong>: Click the <strong>Connect to Folder</strong> button (<strong>STEP 2</strong>).</li><li><strong>Paste &amp; Select</strong>: In the folder picker that appears, paste the path into the address bar at the top and press Enter. Then click <strong>Select Folder</strong>.</li><li><strong>Grant Access</strong>: Click <strong>Select Folder</strong> in the browser&#39;s security popup.</li></ol><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="_1-interactive-hierarchy-tree" tabindex="-1">1. Interactive Hierarchy Tree <a class="header-anchor" href="#_1-interactive-hierarchy-tree" aria-label="Permalink to &quot;1. Interactive Hierarchy Tree&quot;">​</a></h3><p>The sidebar displays the entire UI tree starting from the <code>root</code>.</p><ul><li><strong>Auto-Sync</strong>: The debugger automatically highlights the component you are currently hovering over in-game (note: some elements may not trigger this depending on their configuration).</li><li><strong>Auto-Expand</strong>: Folders automatically open to show the path to the hovered component.</li><li><strong>Manual Selection</strong>: Click any node in the tree to &quot;Lock&quot; the view to that specific component.</li></ul><h3 id="_2-property-inspector" tabindex="-1">2. Property Inspector <a class="header-anchor" href="#_2-property-inspector" aria-label="Permalink to &quot;2. Property Inspector&quot;">​</a></h3><p>The main panel shows all properties of the selected component in real-time.</p><ul><li><strong>Live Updates</strong>: Values like <code>Position</code>, <code>Width</code>, and <code>Text</code> update instantly as they change in-game.</li><li><strong>Direct Editing</strong>: Change values (like <code>Visible</code>, <code>Priority</code>, or <code>Text</code>) directly in the browser. The changes are sent back to the game immediately.</li><li><strong>Actions</strong>: Trigger actions like <code>SimulateClick</code>, <code>DestroyChildren</code>, or <code>Layout</code> with a single click.</li></ul><h3 id="_3-lock-follow-mode" tabindex="-1">3. Lock &amp; Follow Mode <a class="header-anchor" href="#_3-lock-follow-mode" aria-label="Permalink to &quot;3. Lock &amp; Follow Mode&quot;">​</a></h3><p>In the inspector header, you can toggle between two modes:</p><ul><li><strong>🖱️ FOLLOWING MOUSE</strong>: (Default) The inspector automatically switches to whatever you hover over in the game.</li><li><strong>🔒 LOCKED</strong>: The inspector stays on the current component, allowing you to move your mouse without losing your place.</li></ul><h3 id="_4-global-search" tabindex="-1">4. Global Search <a class="header-anchor" href="#_4-global-search" aria-label="Permalink to &quot;4. Global Search&quot;">​</a></h3><p>Use the search bar at the top of the sidebar to find components by:</p><ul><li><strong>ID</strong> (e.g., <code>button_ok</code>)</li><li><strong>Address</strong> (e.g., <code>0x12345</code>)</li><li><strong>Text content</strong> (e.g., &quot;Declare War&quot;)</li><li><strong>Tooltip text</strong></li></ul><p>Matches are highlighted in the tree, and you can navigate through multiple results using the arrow buttons.</p><h3 id="_5-drag-and-drop-hierarchy-manipulation" tabindex="-1">5. Drag and Drop (Hierarchy Manipulation) <a class="header-anchor" href="#_5-drag-and-drop-hierarchy-manipulation" aria-label="Permalink to &quot;5. Drag and Drop (Hierarchy Manipulation)&quot;">​</a></h3><p>You can rearrange the UI hierarchy directly from the tree:</p><ul><li><strong>Adopt</strong>: Drag one component onto another to make it a child (calls <code>Adopt</code> in-game).</li><li><strong>Reorder</strong>: Drag a component between its siblings to change its index (calls <code>Adopt</code> with an index).</li></ul><h2 id="workflow-tips" tabindex="-1">Workflow Tips <a class="header-anchor" href="#workflow-tips" aria-label="Permalink to &quot;Workflow Tips&quot;">​</a></h2><h3 id="finding-ids-for-scripts" tabindex="-1">Finding IDs for Scripts <a class="header-anchor" href="#finding-ids-for-scripts" aria-label="Permalink to &quot;Finding IDs for Scripts&quot;">​</a></h3><p>Enable the debugger and hover over any element in the game. The ID will instantly appear in the inspector. This is the fastest way to find targets for <code>consul.ui.find(&quot;id&quot;)</code>.</p><h3 id="testing-ui-states" tabindex="-1">Testing UI States <a class="header-anchor" href="#testing-ui-states" aria-label="Permalink to &quot;Testing UI States&quot;">​</a></h3><p>You can manually change the <code>CurrentState</code> of a component in the inspector to see how it looks in different states (e.g., <code>hover</code>, <code>active</code>, <code>down</code>) without actually interacting with it in-game.</p><h3 id="persistent-customization" tabindex="-1">Persistent Customization <a class="header-anchor" href="#persistent-customization" aria-label="Permalink to &quot;Persistent Customization&quot;">​</a></h3><ul><li><strong>Hide Properties</strong>: If there are properties you never use, click the <code>×</code> next to them. This preference is saved in your browser&#39;s local storage.</li><li><strong>Restore</strong>: Use the &quot;Restore Hidden&quot; button to bring them back.</li></ul><h3 id="capture-toggle-f7-f5-in-tob" tabindex="-1">Capture Toggle (F7 / F5 in ToB) <a class="header-anchor" href="#capture-toggle-f7-f5-in-tob" aria-label="Permalink to &quot;Capture Toggle (F7 / F5 in ToB)&quot;">​</a></h3><p>You can pause the game-side data stream by pressing <strong>F7</strong> (or <strong>F5</strong> in ToB) in-game. This stops the game from writing updates to the state file, which is useful if you want to freeze the entire debugger state.</p><h2 id="how-it-works-technical-overview" tabindex="-1">How It Works (Technical Overview) <a class="header-anchor" href="#how-it-works-technical-overview" aria-label="Permalink to &quot;How It Works (Technical Overview)&quot;">​</a></h2><p>The UI Debugger uses a &quot;File-based Bridge&quot; to communicate between the game engine and your web browser.</p><h3 id="_1-game-side-lua" tabindex="-1">1. Game Side (Lua) <a class="header-anchor" href="#_1-game-side-lua" aria-label="Permalink to &quot;1. Game Side (Lua)&quot;">​</a></h3><p>The game acts as the <strong>Data Provider</strong>. When you hover, click, or move components, a Lua script snapshots the UI state and writes it to a local file (<code>consul_debug_ui_state.txt</code>). It also polls a second file (<code>consul_debug_ui_commands.txt</code>) for instructions sent from the browser.</p><h3 id="_2-browser-side-javascript" tabindex="-1">2. Browser Side (JavaScript) <a class="header-anchor" href="#_2-browser-side-javascript" aria-label="Permalink to &quot;2. Browser Side (JavaScript)&quot;">​</a></h3><p>The browser acts as the <strong>Interface</strong>. When you click &quot;Connect&quot;, it uses the File System Access API to monitor the state file. It polls the file for changes every 250ms and updates the visual tree. When you trigger an action in the browser, it writes a command to the command file for the game to execute.</p><h3 id="_3-the-bridge" tabindex="-1">3. The Bridge <a class="header-anchor" href="#_3-the-bridge" aria-label="Permalink to &quot;3. The Bridge&quot;">​</a></h3><p>The local filesystem serves as the communication layer. This allows for a &quot;live&quot; experience without needing an external web server or complex network protocols, keeping the tool lightweight and compatible with the game&#39;s restricted environment.</p>',45))])}const f=a(l,[["render",h]]);export{b as __pageData,f as default};
